      out.write("    ];\r\n");
      out.write("\r\n");
      out.write("    let total = 0;\r\n");
      out.write("    candidatos.forEach(c => { total += c.votos; });\r\n");
      out.write("\r\n");
      out.write("    let acumulado = 0;\r\n");
      out.write("    let gradient = \"\";\r\n");
      out.write("    candidatos.forEach(c => {\r\n");
      out.write("        let porcentaje = (c.votos * 100) / total;\r\n");
      out.write("        gradient += `${c.color} ${acumulado}% ${acumulado + porcentaje}%,`;\r\n");
      out.write("        acumulado += porcentaje;\r\n");
      out.write("    });\r\n");
      out.write("\r\n");
      out.write("    gradient = gradient.slice(0,-1);\r\n");
      out.write("    document.getElementById('graficoCircular').style.background = `conic-gradient(${gradient})`;\r\n");
      out.write("\r\n");
      out.write("    let html = \"\";\r\n");
      out.write("    candidatos.forEach(c => {\r\n");
      out.write("        let porcentaje = ((c.votos * 100) / total).toFixed(1);\r\n");
      out.write("        html += `\r\n");
      out.write("        <div class=\"resultado-item\">\r\n");
      out.write("            <div class=\"d-flex justify-content-between align-items-center\">\r\n");
      out.write("                <div class=\"d-flex align-items-center\">\r\n");
      out.write("                    <span class=\"color\" style=\"background:${c.color}\"></span>\r\n");
