      out.write("                </div>\r\n");
      out.write("                <strong>${porcentaje}%</strong>\r\n");
      out.write("            </div>\r\n");
      out.write("        </div>`;\r\n");
      out.write("    });\r\n");
      out.write("\r\n");
      out.write("    document.getElementById('listaResultados').innerHTML = html;\r\n");
      out.write("    candidatos.sort((a,b)=> b.votos - a.votos);\r\n");
      out.write("\r\n");
      out.write("    let ganador = candidatos[0];\r\n");
      out.write("    let porcentajeGanador = ((ganador.votos * 100) / total).toFixed(1);\r\n");
      out.write("\r\n");
      out.write("    document.getElementById('ganadorNombre').innerText = ganador.nombre;\r\n");
